jQuery,app.modals.OrganizationUnitLookupTableModal=function(){var n,e;this.init=function(t){n=t,(e=new OrganizationTree).init(n.getModal().find(".organization-tree"),{cascadeSelectEnabled:!1}),n.getModal().find(".save-button").click((function(){var t=e.getSelectedOrganizations();n.setResult(t),n.close()}))}};